def validate_cart_items(cart: List[CartItem]) -> float:
    subtotal = 0.0
    for item in cart:
        product = PRODUCTS.get(item.product_id)
        if not product:
            raise CheckoutError(f"Invalid product ID: {item.product_id}")
        if item.quantity <= 0:
            raise CheckoutError(f"Quantity must be positive for {item.product_id}")
        if item.quantity > product.stock:
            raise CheckoutError(f"Insufficient stock for {product.name}")
        subtotal += product.price * item.quantity
    return subtotal


def apply_discount(user: User, subtotal: float, code_str: Optional[str]) -> float:
    if not code_str:
        return 0.0
    code = DISCOUNT_CODES.get(code_str)
    if not code:
        raise CheckoutError("Invalid discount code")
    if code.admin_only and not user.is_admin:
        raise CheckoutError("Discount code restricted to administrators")
    if code.allowed_tiers and user.tier not in code.allowed_tiers:
        raise CheckoutError("Discount code not valid for your tier")
    return subtotal * code.percent


def calculate_tax(amount: float, location: str) -> float:
    TAX_RATES = {"NY": 0.08875, "CA": 0.0725, "TX": 0.0625}
    rate = TAX_RATES.get(location, 0.07)
    return amount * rate


