def create_order_record(user: User, cart: List[CartItem], subtotal: float,
                        discount: float, tax: float, total: float,
                        payment_confirmed: bool) -> Order:
    order_id = f"O{len(ORDERS)+1:06d}"
    order = Order(order_id, user.user_id, cart, subtotal, discount,
                  tax, total, payment_confirmed)
    ORDERS[order_id] = order
    # Decrement stock
    for item in cart:
        PRODUCTS[item.product_id].stock -= item.quantity
    return order


# -------------------- Main Checkout Function --------------------
def checkout(user: User, cart: List[CartItem], discount_code: Optional[str],
             payment_info: Dict) -> Order:
    # Step 1: Validate cart items
    subtotal = validate_cart_items(cart)

    # Step 2: Apply discount codes
    discount = apply_discount(user, subtotal, discount_code)
    subtotal_after_discount = subtotal - discount

    # Step 3: Calculate tax
    tax = calculate_tax(subtotal_after_discount, user.location)

    # Step 4: Process payment
    total = subtotal_after_discount + tax
    payment_confirmed = process_payment(user, total, payment_info)
    if not payment_confirmed:
        raise CheckoutError("Payment processing failed")

    # Step 5: Create order record
    order = create_order_record(user, cart, subtotal, discount, tax, total, payment_confirmed)
    return order


